import { _decorator, Component, director, Node, Label, Button, ScrollView, Prefab, instantiate, Vec3 } from 'cc';
import { GameManager } from '../Core/GameManager';
import { Utils } from '../Utils/Utils';

const { ccclass, property } = _decorator;

@ccclass('BlackMarketScene')
export class BlackMarketScene extends Component {
    @property(Button)
    backBtn: Button = null;
    
    @property(Label)
    timeLabel: Label = null;
    
    @property(Label)
    warningLabel: Label = null;
    
    @property(ScrollView)
    itemListScrollView: ScrollView = null;
    
    @property(Node)
    blackMarketItemPrefab: Node = null;
    
    @property(Label)
    reputationLabel: Label = null;
    
    private isOpen = false;
    private reputation = 50; // 黑市信誉度
    
    // 黑市商品（违禁品）
    private blackMarketItems = [
        { id: 'stolen_goods', name: '来路不明的供品', type: 'forbidden', price: 500, currency: 'incense_money', desc: '可能是从其他庙宇偷来的', risk: 0.3 },
        { id: 'cursed_item', name: '诅咒的法器', type: 'forbidden', price: 2000, currency: 'incense_money', desc: '带有不祥的气息', risk: 0.5 },
        { id: 'banned_scroll', name: '禁术秘籍', type: 'illegal', price: 5000, currency: 'yuanbao', desc: '被天庭禁止的修炼方法', risk: 0.7 },
        { id: 'stolen_relic', name: '失传的宝物', type: 'stolen', price: 10000, currency: 'yuanbao', desc: '从博物馆偷来的古董', risk: 0.8 },
        { id: 'corrupt_blessing', name: '腐败的祝福', type: 'corrupt', price: 3000, currency: 'merit', desc: '用功德换取的邪恶力量', risk: 0.6 },
        { id: 'fake_id', name: '假身份令牌', type: 'forbidden', price: 800, currency: 'yuanbao', desc: '可以伪装成其他玩家', risk: 0.4 }
    ];
    
    onLoad() {
        this.backBtn.node.on(Button.EventType.CLICK, this.onBack, this);
    }
    
    start() {
        this.checkOpenTime();
        this.schedule(this.checkOpenTime, 60); // 每分钟检查
        this.updateItemList();
        this.reputationLabel.string = `黑市信誉: ${this.reputation}`;
    }
    
    checkOpenTime() {
        const now = new Date();
        const hour = now.getHours();
        
        // 黑市开放时间: 21:00 - 23:00
        this.isOpen = (hour >= 21 && hour < 23);
        
        if (this.isOpen) {
            const minsLeft = (23 - hour) * 60 - now.getMinutes();
            this.timeLabel.string = `黑市开放中！剩余${minsLeft}分钟`;
            this.timeLabel.color = {r: 255, g: 0, b: 0, a: 255};
            this.warningLabel.string = '⚠️ 购买违禁品可能降低功德或被天庭追查！';
        } else {
            let nextOpen = '';
            if (hour < 21) {
                nextOpen = `今晚21:00开放（还有${21 - hour}小时）`;
            } else {
                nextOpen = '已关闭，明晚21:00开放';
            }
            this.timeLabel.string = `黑市关闭中 - ${nextOpen}`;
            this.timeLabel.color = {r: 128, g: 128, b: 128, a: 255};
            this.warningLabel.string = '';
        }
    }
    
    updateItemList() {
        const content = this.itemListScrollView.content;
        content.removeAllChildren();
        
        if (!this.isOpen) return;
        
        for (const item of this.blackMarketItems) {
            const node = instantiate(this.blackMarketItemPrefab);
            
            node.getChildByName('NameLabel').getComponent(Label).string = item.name;
            node.getChildByName('TypeLabel').getComponent(Label).string = `[${item.type}]`;
            node.getChildByName('PriceLabel').getComponent(Label).string = `${item.price} ${item.currency}`;
            node.getChildByName('DescLabel').getComponent(Label).string = item.desc;
            node.getChildByName('RiskLabel').getComponent(Label).string = `风险: ${(item.risk * 100).toFixed(0)}%`;
            
            const buyBtn = node.getChildByName('BuyBtn').getComponent(Button);
            buyBtn.node.on(Button.EventType.CLICK, () => this.onBuy(item), this);
            
            content.addChild(node);
        }
    }
    
    onBuy(item: any) {
        if (!this.isOpen) {
            console.log('黑市未开放');
            return;
        }
        
        const player = GameManager.getInstance().playerData;
        
        if (!player.costCurrency(item.currency, item.price)) {
            console.log('货币不足');
            return;
        }
        
        // 判定是否被追查
        if (Math.random() < item.risk) {
            // 被天庭追查
            const penalty = Math.floor(item.price * 0.5);
            player.costCurrency('merit', penalty);
            this.reputation = Math.max(0, this.reputation - 10);
            alert(`⚠️ 被天庭追查！扣除${penalty}功德，黑市信誉下降`);
        } else {
            // 购买成功
            this.reputation = Math.min(100, this.reputation + 5);
            alert(`✅ 成功购买${item.name}，黑市信誉上升`);
        }
        
        this.reputationLabel.string = `黑市信誉: ${this.reputation}`;
    }
    
    onBack() {
        director.loadScene('MainScene');
    }
    
    onDestroy() {
        this.unscheduleAllCallbacks();
    }
}
